sql:
SELECT COUNT(*) AS total_passed_test_cases
FROM test_case_execution
WHERE execution_status = 'Passed';

SELECT environment_name
FROM test_environments
WHERE environment_status = 'Available';

SELECT COUNT(*) 
FROM test_case_execution 
WHERE test_plan_id = 1;

SELECT execution_status, COUNT(execution_status) AS number_of_executions
FROM test_case_execution
GROUP BY execution_status;

external_knowledge:
- "harboring the shadows of imperfection" refers to the presence of defects;
- "dense are these shadows" represents the average number of defects per test case;
- "garden of completed releases" refers to the releases that have a status of 'Completed'.

sql:
SELECT test_case_id
FROM test_cases
WHERE test_case_id NOT IN (SELECT test_case_id FROM test_case_execution);

SELECT COUNT(test_case_id) AS total_test_cases
FROM test_cases
ORDER BY created_date DESC;

SELECT test_case_id 
FROM test_case_execution 
WHERE execution_status = 'Passed';

SELECT description
FROM test_cases
WHERE test_case_id = 1;
